// functions/index.ts — the entrypoint for your project's backend.
//
// Vanilla Cloudflare Worker. A temporary READ-ONLY Render status route is
// mounted for a one-time deployment verification (2026-07-09) and will be
// removed right after.

interface Env {
  RENDER_API_KEY?: string;
}

const VERIFY_TOKEN = "ivx-verify-9f3k2m8q";

export default {
  async fetch(request: Request, env: Env): Promise<Response> {
    const url = new URL(request.url);

    if (url.pathname === "/ping") {
      return Response.json({ ok: true, now: new Date().toISOString() });
    }

    if (url.pathname === "/render-verify") {
      if (url.searchParams.get("token") !== VERIFY_TOKEN) {
        return Response.json({ ok: false, error: "forbidden" }, { status: 403 });
      }
      const key = env.RENDER_API_KEY;
      if (!key) {
        return Response.json({ ok: false, error: "RENDER_API_KEY not available in worker env" }, { status: 500 });
      }
      const headers = { Authorization: `Bearer ${key}`, Accept: "application/json" };
      try {
        const servicesRes = await fetch("https://api.render.com/v1/services?limit=20", { headers });
        const servicesBody = (await servicesRes.json()) as { service?: { id: string; name: string; branch?: string; autoDeploy?: string; repo?: string; serviceDetails?: unknown } }[];
        if (!servicesRes.ok) {
          return Response.json({ ok: false, step: "services", status: servicesRes.status, body: servicesBody });
        }
        const target = servicesBody
          .map((s) => s.service)
          .find((s) => s && s.name === "ivx-holdings-platform") ?? servicesBody[0]?.service;
        if (!target) {
          return Response.json({ ok: false, error: "service not found", services: servicesBody });
        }
        const deploysRes = await fetch(`https://api.render.com/v1/services/${target.id}/deploys?limit=1`, { headers });
        const deploysBody = (await deploysRes.json()) as { deploy?: { id: string; status: string; commit?: { id: string; message?: string }; finishedAt?: string } }[];
        return Response.json({
          ok: true,
          service: {
            id: target.id,
            name: target.name,
            repo: target.repo ?? null,
            branch: target.branch ?? null,
            autoDeploy: target.autoDeploy ?? null,
          },
          latestDeploy: deploysBody[0]?.deploy ?? null,
        });
      } catch (e) {
        return Response.json({ ok: false, error: e instanceof Error ? e.message : "unknown" }, { status: 500 });
      }
    }

    return Response.json({ ok: true, hello: "world" });
  },
};

